<template>
  <div class="container mt-6 mt-md-15 flex-shrink-0 flex-grow-1">
    <div class="row">
      <main class="col-md-7 col-xl-4 mx-auto">
        <h2 class="mb-4">
          <IconTitle title="會員登入" />
        </h2>

        <VeeForm v-slot="{ errors }" class="d-flex flex-column" @submit="login">
          <!-- 帳號 -->
          <div class="mb-4">
            <label for="account" class="form-label">帳號</label>
            <VeeField
              type="text"
              name="account"
              id="account"
              :class="['form-control', errors.account ? 'is-invalid' : '']"
              placeholder="請輸入帳號"
              rules="required"
              label="帳號"
              v-model="form.account"
            />
            <VeeErrorMessage name="account" class="invalid-feedback" />
          </div>

          <!-- 密碼 -->
          <div class="mb-6 mb-md-8">
            <label for="password" class="form-label">密碼</label>
            <VeeField
              type="password"
              name="password"
              id="password"
              :class="['form-control', errors.password ? 'is-invalid' : '']"
              placeholder="請輸入密碼"
              rules="required"
              label="密碼"
              v-model="form.password"
            />
            <VeeErrorMessage name="password" class="invalid-feedback" />
          </div>

          <button
            class="btn btn-primary py-4 py-md-2 fs-18 fs-md-20 lh-1d444 lh-md-1d45 d-flex justify-content-center align-items-center w-100"
          >
            <span class="me-1">登入</span>
            <i class="icofont-rounded-double-right"></i>
          </button>
        </VeeForm>
      </main>
    </div>
  </div>
</template>

<script>
import { mapActions, mapState } from "pinia";
import { useLoadingStore, useUserStore } from "@/stores";
import {
  ConfirmAlert,
  CookieHelper,
  CountdownCallbackParam,
  ErrorHelper,
  SysConstants,
  TimerAlert,
} from "@/helpers";
import { AuthService } from "@/services";
import IconTitle from "@/components/global/IconTitle.vue";

export default {
  data() {
    return {
      // 表單資料
      form: {
        account: "test@7tao.com",
        password: "A123456789",
      },
    };
  },

  methods: {
    /** loading 功能 */
    ...mapActions(useLoadingStore, {
      openLoading: "open",
      closeLoading: "close",
    }),

    // TODO TEST
    ...mapActions(useUserStore, {
      getUserString: "toString",
    }),

    /**
     * 登入。
     */
    login() {
      this.openLoading();
      console.log("登入資料：", this.form);

      AuthService.login(this.form.account, this.form.password)
        .then((user) => {
          console.log(`[login] 登入成功：`, user);
          console.log(`cookie ====>`, CookieHelper.getCookie(SysConstants.cookieTokenName));
          console.log(this.getUserString());

          this.switchPage();
        })
        .catch((error) => {
          console.error(`[login] 登入失敗：`, error);
          ConfirmAlert.alertErrorDetail("登入失敗", ErrorHelper.getErrorMsg(error));
        })
        .finally(() => {
          this.closeLoading();
        });
    },

    // TODO test
    switchPage() {
      const callback = () => {
        // alert("登入!");
        this.$router.push("/");
      };

      const param = new CountdownCallbackParam(2);
      param.title = "登入成功！";
      param.desc = "將自動轉到首頁。";
      param.callback = callback;

      TimerAlert.alertCountdownCallback(param);
    },
  },

  computed: {
    // TODO TEST
    ...mapState(useUserStore, {
      id: "id",
      userName: "name",
      userEmail: "email",
    }),

    // TODO TEST
    userString() {
      return this.getUserString();
    },
  },

  watch: {},
  components: { IconTitle },
};
</script>
